"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Create your account",
    content:
      "Set up your email address and password. You'll use these credentials to log in.",
  },
  {
    step: 2,
    title: "Profile",
    description: "Set up your profile",
    content:
      "Tell us a bit about yourself. Add your name, avatar, and any other details you'd like to share.",
  },
  {
    step: 3,
    title: "Complete",
    description: "Review and finish",
    content:
      "Everything looks great! Review your details and click Finish to complete the setup.",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  function handlePrev() {
    setActiveStep((prev) => Math.max(1, prev - 1))
  }

  function handleNext() {
    setActiveStep((prev) => Math.min(steps.length, prev + 1))
  }

  return (
    <div className="w-full max-w-2xl space-y-8 px-4">
      <Stepper activeStep={activeStep}>
        {steps.map((s, index) => (
          <React.Fragment key={s.step}>
            <StepperItem step={s.step} className="flex-col items-center gap-2">
              <StepperTrigger
                onClick={() => setActiveStep(s.step)}
                aria-label={`Go to step ${s.step}: ${s.title}`}
              />
              <div className="hidden text-center sm:block">
                <StepperTitle>{s.title}</StepperTitle>
                <StepperDescription>{s.description}</StepperDescription>
              </div>
            </StepperItem>
            {index < steps.length - 1 && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>

      {steps.map((s) => (
        <StepperContent key={s.step} step={s.step}>
          <div className="rounded-lg border p-6">
            <h3 className="font-semibold">{s.title}</h3>
            <p className="mt-1 text-sm text-muted-foreground">{s.content}</p>
          </div>
        </StepperContent>
      ))}

      <div className="flex gap-2">
        <Button
          variant="outline"
          onClick={handlePrev}
          disabled={activeStep === 1}
        >
          Previous
        </Button>
        <Button onClick={handleNext} disabled={activeStep === steps.length}>
          {activeStep === steps.length - 1 ? "Finish" : "Next"}
        </Button>
      </div>
    </div>
  )
}

